      );
    }
    if (!nullToAbsent || savingId != null) {
      map['saving_id'] = Variable<String>(savingId);
    }
    if (!nullToAbsent || targetSavingId != null) {
      map['target_saving_id'] = Variable<String>(targetSavingId);
    }
    if (!nullToAbsent || payeeId != null) {
